"},"$:/plugins/Gk0Wk/CPL-Repo/styles/comment-styles":{"title":"$:/plugins/Gk0Wk/CPL-Repo/styles/comment-styles","created":"20260101000000000","modified":"20260101000000000","tags":"$:/tags/Stylesheet","type":"text/css","text":".cpl-comment-section{font-family:inherit}.cpl-comment-section h3{color:#333;font-size:1.2em}.cpl-comment-textarea{font-size:14px;line-height:1.5}.cpl-comment-textarea:focus{outline:0;border-color:#4a90e2;box-shadow:0 0 0 2px rgba(74,144,226,.2)}.cpl-comments-list{margin-top:16px}.cpl-comments-list>div:last-child{border-bottom:none}.tc-story-river .cpl-comment-section,[data-tiddlywiki-theme-name=Dark] .cpl-comment-section{background:#2d2d2d;border-color:#444}.tc-story-river .cpl-comment-section h3,[data-tiddlywiki-theme-name=Dark] .cpl-comment-section h3{color:#e0e0e0;border-color:#444}.tc-story-river .cpl-comment-textarea,[data-tiddlywiki-theme-name=Dark] .cpl-comment-textarea{background:#1e1e1e;color:#e0e0e0;border-color:#555}"},"$:/plugins/Gk0Wk/CPL-Repo/styles/cpl.css":{"title":"$:/plugins/Gk0Wk/CPL-Repo/styles/cpl.css","created":"20231009122025301","modified":"20231011071732554","tags":"$:/tags/Stylesheet","type":"text/vnd.tiddlywiki","text":".cpl-normal-button {
  color: <<colour foreground>>;
  fill: color: <<colour foreground>>;
}

.cpl-plugin-info-box {
  overflow: hidden;
  border: 1px solid <<colour tiddler-info-border>>;
  background-color: <<colour tiddler-info-background>>;
}
.cpl-plugin-dependencies {
  border-left: 0.8px solid <<colour tiddler-info-border>>;
  border-right: 0.8px solid <<colour tiddler-info-border>>;
}

.cpl-plugin-info-box > .tc-plugin-info {
  margin: 0 !important;
  border: none !important;
}

.cpl-plugin-info-box > .tc-plugin-info-dropdown {
  margin-top: 0 !important;
  border: none !important;
}

.cpl-plugin-info-box > .tc-plugin-info-dropdown,
.cpl-plugin-info-box > .tc-plugin-info-dropdown > .tc-plugin-info-dropdown-message,
.cpl-plugin-info-box > .tc-plugin-info-dropdown > .tc-plugin-info-dropdown-body {
  background: transparent !important;
  background-color: transparent !important;
}

.cpl-plugin-info-box > .tc-plugin-info-dropdown > .tc-plugin-info-dropdown-body {
  box-shadow: inset 0 12px 12px -12px rgba(0, 0, 0, 0.3);
}

.cpl-latest-version-icon > svg, .cpl-installed-version-icon > svg {
  height: 1em;
  width: 1em;
}

.cpl-latest-version-icon > svg {
  color: #FFC107;
  fill: #FFC107;
}

.cpl-installed-version-icon > svg {
  color: #3ccb0f;
  fill: #3ccb0f;
}

.cpl-plugin-install-request-dependents-tree {
  border-left:2px dotted <<colour very-muted-foreground>>;
  background: #0002;
}

.cpl-plugin-search {
  flex-grow: 1;
  width: 0;
}

.cpl-plugin-search span {
  display: inline-block;
  width: 100%;
}

.cpl-plugin-search span input {
  margin: 0 !important;
  width: 100%;
}

.cpl-plugin-search-go {
  border-radius: 0 !important;
  margin: 0 !important;
  padding: 10px 20px !important;
  word-break: keep-all;
}

.cpl-paged-plugin-list-control {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 40px;
  border: 2px solid <<colour tiddler-info-border>>;
  background-color: <<colour tiddler-info-background>>;
}

.cpl-paged-plugin-list-control > div {
  flex-grow: 1;
  width: 0;
  height: 100%;
}

.cpl-paged-plugin-list-control > div > button {
  width: 100%;
  height: 100%;
  border: none !important;
  background: transparent !important;
  cursor: pointer !important;
}

.cpl-paged-plugin-list-control > div > button:hover {
  backdrop-filter: contrast(0.75);
}

.cpl-paged-plugin-list-control > span {
  padding: 0 10px;
  height: 100%;
  display: flex;
  align-items: center;
  user-select: none;
}

.cpl-banner-container {
  padding: 26px 16px;
  background: #1f5ea3;
  border-left: 5px solid #acc8d4;
  display:inline-block;
  background-image: linear-gradient(45deg, #1f5ea3, #1f71a3);
  width: 100%;
}
.cpl-banner-button-group svg {
  height: 1em;
  width: 1em;
}

.cpl-layout-container {
  display: flex;
  flex-direction: column;
  align-items: stretch;
  height: 100%;
  width: 100%;
  padding: 0.5em;
}

.cpl-action-bar {
  display: flex;
  align-items: center;
  gap: 10px;
  flex-wrap: wrap;
  margin-bottom: 10px;
}

.cpl-action-button {
  display: inline-flex;
  align-items: center;
  gap: 0.35em;
}

.cpl-action-toggle {
  display: inline-flex;
  align-items: center;
  min-height: 2.3em;
  padding: 0 0.8em;
  border-radius: 999px;
  border: 1px solid <<colour tiddler-info-border>>;
  background: <<colour tiddler-info-background>>;
}

.cpl-action-toggle input {
  margin-right: 0.45em;
}

.cpl-action-toggle-label {
  font-size: 0.92em;
}

.cpl-action-pill {
  display: inline-flex;
  align-items: center;
  min-height: 2.3em;
  padding: 0 0.8em;
  border-radius: 999px;
  background: rgba(60, 179, 113, 0.12);
  color: #1d6c3e;
  font-size: 0.9em;
  font-weight: 600;
}

.cpl-action-pill-muted {
  background: rgba(128, 128, 128, 0.14);
  color: <<colour muted-foreground>>;
}

/* Disable dut to high GPU usage */
/**
.cpl-website-mainpage-search-bar {
  animation: breath-glow 1.5s infinite alternate;
}
*/

@keyframes breath-glow {
  from {
    box-shadow: 0 0 5px rgba(0, 123, 255, 0.5);
  }
  to {
    box-shadow: 0 0 20px rgba(0, 123, 255, 1);
  }
}

/* Mirror Switcher Styles */
.cpl-mirror-switcher {
  display: inline-flex;
  align-items: center;
  gap: 8px;
}

.cpl-mirror-select {
  font-size: 0.9em;
  transition: border-color 0.2s ease;
}

.cpl-mirror-select:hover {
  border-color: #999;
}

.cpl-mirror-select:focus {
  outline: none;
  border-color: #1f5ea3;
  box-shadow: 0 0 0 2px rgba(31, 94, 163, 0.1);
}

.cpl-mirror-status {
  white-space: nowrap;
  font-weight: 500;
}

.cpl-mirror-server {
  color: #28a745;
}

.cpl-mirror-static {
  color: #ffc107;
}

.cpl-mirror-unknown {
  color: #999;
}

/* Static Mirror Notice Styles */
.cpl-static-mirror-notice,
.cpl-static-feature-notice {
  animation: fade-in 0.3s ease;
}

@keyframes fade-in {
  from {
    opacity: 0;
    transform: translateY(-4px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}
