           border-radius: 6px;
           overflow: hidden;
           margin: 40px 0 0 0;
           border-top: 1px #03A9F4 dashed;
           border-bottom: 1px #FFC107 dashed;">
    <h2 style="border-left: 3px #e91e63 solid; padding-left: 4px;">
        <$text text={{{ [<chinese>match[yes]then[特别鸣谢]else[Specially thanks to]] }}}/>
    </h2>
    <div>
        <$text text={{{ [<chinese>match[yes]then[登记人]else[Registrant]] }}}/>:
            <$text text={{!!creator}} />&nbsp;&nbsp;<span style="opacity: 0.5">
                <$view field="created" format="date" template={{$:/language/Tiddler/DateFormat}} />
            </span>
    </div>
    <div>
        <$text text={{{ [<chinese>match[yes]then[最后编辑]else[Last modified]] }}}/>:
            <$text text={{!!modifier}} />&nbsp;&nbsp;<span style="opacity: 0.5">
                <$view field="modified" format="date" template={{$:/language/Tiddler/DateFormat}} />
            </span>
    </div>
</div>

<!-- 作者的其他插件 -->
<$list filter="[{!!cpl.author}!is[blank]]" variable="t">
<details open>
    <summary>
        <$text text={{{ [<chinese>match[yes]then[作者的其他插件]else[Author's other plugins]] }}} />
    </summary>
    <div style="padding:6px;display:flex;flex-direction:row;overflow-x:auto;">
        <$let authorPattern={{{ [{!!cpl.title}removeprefix[$:/]split[/]first[2]last[]addprefix[/]addsuffix[/]] }}}>
            <$list
                filter="[search:cpl.title<authorPattern>] [field:cpl.author{!!cpl.author}] +[!field:title<currentTiddler>unique[]shuffle[]]"
                variable="plugin">
                <$macrocall $name="plugin-item" title=<<plugin>> class="row-scroll-plugin-item" />
            </$list>
        </$let>
    </div>
</details>
</$list>

<$list filter="[all[current]has[cpl.category]then{!!cpl.category}else[Unknown]]" variable="category">
<$list filter="[<category>!match[Unknown]!is[blank]]" variable="t">
<details open>
    <summary>
        <$text text={{{ [<chinese>match[yes]then[同类插件]else[Similar plugins]] }}} />
    </summary>
    <div style="padding:6px;display:flex;flex-direction:row;overflow-x:auto;">
        <$list filter="[field:cpl.category<category>] +[!field:title<currentTiddler>unique[]shuffle[16]]" variable="plugin">
            <$macrocall $name="plugin-item" title=<<plugin>> class="row-scroll-plugin-item" />
        </$list>
    </div>
</details>
</$list>
</$list>

</$list>
"},"$:/plugins/Gk0Wk/CPL-Repo/templates/cpl/tag-picker":{"title":"$:/plugins/Gk0Wk/CPL-Repo/templates/cpl/tag-picker","code-body":"yes","created":"20231010211850384","modified":"20231010214712649","tags":"","type":"text/vnd.tiddlywiki","text":"\define tag-plain(text:"",icon:"",color:"",bg:"")
\whitespace trim
<span class="tc-tag-label" style="background-color:$bg$;color:$color$;fill:$color$;user-select:none;margin-right:6px;">
	{{$icon$}}$text$
</span>
\end

\define tag-plain-removable(saveTiddler,saveField:"tags",text:"",icon:"",color:"",bg:"")
\whitespace trim
<span class="tc-tag-label" style="background-color:$bg$;color:$color$;fill:$color$;user-select:none;margin:4px 6px 2px 0;padding:4px 10px;">
	{{$icon$}}$text$
	<$button class="tc-btn-invisible tc-remove-tag-button" style="background-color:$bg$;color:$color$;fill:$color$;">
		<$action-listops $tiddler=<<__saveTiddler__>> $field=<<__saveField__>> $subfilter="-[<__text__>]"/>{{$:/core/images/close-button}}
	</$button>
</span>
\end

\define cpl-tag-picker(title,field:"cpl.tags")
<$let 
    bg={{{ [{$:/palette}getindex[tag-background]] }}}
    color={{{ [{$:/palette}getindex[foreground]] }}}
    saveTiddler="$title$"
    saveField=<<__field__>>
    inputTitle=<<qualify "$:/temp/CPL/tag-picker-input">>
    popupTitle=<<qualify "$:/temp/CPL/tag-picker-popup">>
>
<div style="width:100%;display:flex;backdrop-filter:contrast(1.3);">
<div class="cpl-search-tags" style="flex-grow:1;width:0;display:flex;align-items:center;padding:4px 8px;flex-wrap:wrap;">
    <!-- 已有的标签，可删除 -->
    <$list filter="[<__title__>get<saveField>enlist-input[]]" variable="tag">
    <$macrocall $name="tag-plain-removable" text=<<tag>> icon="$:/core/images/tag-button" bg=<<bg>> color=<<color>> saveTiddler=<<__title__>> saveField=<<saveField>> />
    </$list>
    <div class="cpl-search-tags-input">
        <!-- 输入 -->
        <$macrocall
            $name="keyboard-driven-input"
            tiddler=<<inputTitle>>
            tag="input"
            placeholder={{$:/language/EditTemplate/Tags/Add/Placeholder}}
            focusPopup=<<popupTitle>>
            class="tc-edit-texteditor tc-popup-handle"
            tabindex=<<tabIndex>>
            focus="no"
            filterMinLength="2"
            configTiddlerFilter="[[$:/core/macros/tag-picker]]"
            inputAcceptActions="<$action-listops $tiddler=<<__title__>> $field=<<saveField>> $subfilter='[<inputTitle>get[text]]'/>"
        />
        <!-- 弹出 -->
        <$reveal state=<<popupTitle>> type="nomatch" text="" default="">
        <div class="tc-block-dropdown tc-block-tags-dropdown">
            <$list filter="[tag[$:/tags/PluginWiki]get[cpl.tags]enlist-input[]unique[]]" variable="tag">
            <$button class="tc-btn-invisible" tag="a" tooltip={{$:/language/EditTemplate/Tags/Add/Button/Hint}}>
                <$macrocall $name="tag-plain" text=<<tag>> icon="$:/core/images/tag-button" bg=<<bg>> color=<<color>> />
                <$action-listops $tiddler=<<__title__>> $field=<<saveField>> $subfilter="[<tag>]"/>
            </$button>
            </$list>
        </div>
        </$reveal>
    </div>
</div>
</div>
</$let>
\end"},"$:/plugins/Gk0Wk/CPL-Repo/templates/cpl/view-template-title-1":{"title":"$:/plugins/Gk0Wk/CPL-Repo/templates/cpl/view-template-title-1","code-body":"yes","created":"20231006124003716","modified":"20231006124026230","tags":"","type":"text/vnd.tiddlywiki","text":"\define plugin-info(title,type)
<$set value="$title$" name="currentTiddler">
<div class="tc-plugin-info">
<!-- 图标 -->
<div class="tc-plugin-info-chunk tc-plugin-info-icon">
<$list filter="[<currentTiddler>has[cpl.icon]]" emptyMessage="""<$transclude tiddler=\"$:/core/images/plugin-generic-$type$\"/>""">
<img src={{!!cpl.icon}}/>
</$list>
</div>
<!-- 名称+描述+标题+版本 -->
<div class="tc-plugin-info-chunk tc-plugin-info-description">
<h1><strong><$text text={{{ [<currentTiddler>get[cpl.name]] ~[<currentTiddler>get[cpl.title]split[/]last[1]] }}}/></strong>: <$text text={{{ [<currentTiddler>get[cpl.description]] }}}/></h1>
<h2><$view tiddler=<<currentTiddler>> field="cpl.title"/></h2>
<div><em><$list filter="[all[current]has[cpl.version]]"><$text text={{{ [all[current]get[cpl.version]] }}}/></$list><$list filter="[all[current]!has[cpl.version]]"><$set name="title" value={{{ [all[current]get[cpl.title]] }}}><$text text={{{ [[$:/temp/tw-cpl/plugin-callback-info]getindex<title>split[|]last[]] }}}/></$set></$list></em></div>
</div>
<!-- 是否需要重载 -->
<div class="tc-plugin-info-chunk tc-plugin-info-buttons">
<$set name="title" value={{{ [all[current]get[cpl.title]] }}}><$set name="requiresReload" value={{{ [[$:/temp/tw-cpl/plugin-callback-info]getindex<title>split[|]first[]] }}}><$list filter="[<requiresReload>match[true]]">{{$:/language/ControlPanel/Plugins/PluginWillRequireReload}}</$list></$set></$set>
</div>
</div>
<div class="tc-plugin-info-dropdown">
<$list filter="[enlist{!!cpl.dependents}] [<currentTiddler>get[cpl.parent-plugin]] +[limit[1]] ~[<currentTiddler>get[cpl.title]!is[tiddler]]" variable="ignore">
<div class="tc-plugin-info-dropdown-message">
<$list filter="[<currentTiddler>!is[tiddler]]">
{{$:/language/ControlPanel/Plugins/NotInstalled/Hint}}
</$list>
<$list filter="[enlist{!!cpl.dependents}] [<currentTiddler>get[cpl.parent-plugin]] +[limit[1]]" variable="ignore">
<div>
{{$:/language/ControlPanel/Plugins/AlsoRequires}}
<$list filter="[enlist{!!cpl.dependents}] [{!!cpl.parent-plugin}] +[sort[cpl.name]]" variable="dependency">
<$text text=<<dependency>>/>
</$list>
</div>
</$list>
</div>
</$list>
<div class="tc-plugin-info-dropdown-body">
<$list filter="[<currentTiddler>get[cpl.documentation]!match[]]" variable="url"><$button class="tc-btn-invisible" message="tm-open-external-window" param=<<url>>>{{$:/core/images/home-button}} <$text text=<<url>>/></$button><br/></$list>
<$list filter="[<currentTiddler>get[cpl.source]!match[]]" variable="url"><$button class="tc-btn-invisible" message="tm-open-external-window" param=<<url>>>{{$:/core/images/github}} <$text text=<<url>>/></$button><br/></$list>
<$transclude tiddler=<<currentTiddler>> field="cpl.readme" mode="block"/>
</div>
</div>
</$set>
\end

<div style="display:none;">

<$reveal state="$:/info/tidgi" type="nomatch" text="yes">
{{CallbackInfo}}
</$reveal>

</div>

<$macrocall $name="plugin-info" title=<<currentTiddler>> type={{{ [<currentTiddler>get[_type]else[plugin]] }}}/>"},"$:/plugins/Gk0Wk/CPL-Repo/templates/cpl/view-template-title":{"title":"$:/plugins/Gk0Wk/CPL-Repo/templates/cpl/view-template-title","code-body":"yes","created":"20231006113559506","modified":"20231007064423902","tags":"TW5CPL","type":"text/vnd.tiddlywiki","text":"\whitespace trim

