<$action-sendmessage $message="cpl-query-plugin" title=<<pluginTitle>>/>
</$list>

<$list filter="[<pluginTitle>is[blank]]">
<div style="display: flex; align-items: center; justify-content: center; min-height: 200px; color: #999;">
<$text text={{{ [[$:/language]get[text]removeprefix[$:/languages/]else[en-GB]search[zh]then[请选择一个插件]else[Choose a plugin to view details.]] }}}/>
</div>
</$list>

<!-- Back button -->
<div style="margin-bottom: 16px;">
<$button class="tc-btn-invisible" style="display: inline-flex; align-items: center; gap: 6px; color: #666; font-size: 0.9em;">
<$action-setfield $tiddler="$:/layout" text="$:/plugins/Gk0Wk/CPL-Repo/layout/layout"/>
<$action-setfield $tiddler="$:/plugins/Gk0Wk/CPL-Repo/views/plugins/plugin-detail" cpl.title=""/>
{{$:/core/images/close-button}}
<$text text={{{ [[$:/language]get[text]removeprefix[$:/languages/]else[en-GB]search[zh]then[返回]else[Back]] }}}/>
</$button>
</div>

<$list filter="[<pluginTitle>!is[blank]]">

<!-- Loading state -->
<$list filter="[<detailJsonStateTitle>is[tiddler]field:text[yes]]">
<div style="display: flex; align-items: center; justify-content: center; min-height: 200px; color: #999;">
<$text text={{{ [[$:/language]get[text]removeprefix[$:/languages/]else[en-GB]search[zh]then[加载中...]else[Loading...]] }}}/>
</div>
</$list>

<!-- Error state -->
<$list filter="[<detailJsonStateTitle>is[tiddler]!field:text[yes]]">
<div style="background: #e91e3db0; color: white; padding: 12px; border-radius: 4px; margin-bottom: 16px;">
<$text text={{{ [[$:/language]get[text]removeprefix[$:/languages/]else[en-GB]search[zh]then[出现了一些问题]else[Some errors occured]] }}}/>: <$text text={{!!text}}/> <$text text={{{ [[$:/language]get[text]removeprefix[$:/languages/]else[en-GB]search[zh]then[请尝试刷新]else[Please try refreshing]] }}}/> 
</div>
</$list>

<!-- Plugin Detail Content -->
<$list filter="[<detailJsonStateTitle>!is[tiddler]]">
