<div style="display: flex; align-items: center; gap: 12px; flex-wrap: wrap; margin-bottom: 8px;">
<span style="font-size: 0.85em; color: #888;">v<$text text=<<version>>/></span>
<$list filter="[<author>!is[blank]]">
