<$list filter="[<installedVersion>compare:version:eq<version>]">&nbsp;<span style="color: #28a745;">{{$:/core/images/done-button}}</span></$list>
</span>
<span style="display: flex; gap: 8px; align-items: center;">
<div style="font-size: 0.85em;"><$macrocall $name="install-plugin-button" plugin=<<title>> libraryVersion=<<version>> installedVersion=<<installedVersion>> /></div>
<$button class="tc-btn-invisible" style="font-size: 0.85em; color: #666;" tooltip={{{ [[$:/language]get[text]removeprefix[$:/languages/]else[en-GB]search[zh]then[下载该版本JSON文件]else[Download this version JSON]] }}}>
<$action-sendmessage $message="cpl-download-plugin" plugin=<<title>> version=<<version>> />
{{$:/core/images/save-button}}
</$button>
</span>
</div>
</$list>
</div>
</details>
</$list>

<!-- README -->
<div class="cpl-plugin-readme" style="margin-bottom: 24px;">
